python3 -c "
import socket

def scan_port(ip, port, timeout=0.5):
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(timeout)
        result = sock.connect_ex((ip, port))
        sock.close()
        return result == 0
    except:
        return False

# Scan docker network for port 8929 (GitLab)
for i in range(1, 21):
    ip = f'172.17.0.{i}'
    if scan_port(ip, 8929):
        print(f'Port 8929 open on {ip}')
    if scan_port(ip, 3000):
        print(f'Port 3000 open on {ip}')
"

