import socket

# Try to enumerate hosts on the docker bridge network
# My IP is 172.17.0.8, let me try to find other containers

def check_port(ip, port, timeout=0.3):
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(timeout)
        result = sock.connect_ex((ip, port))
        sock.close()
        return result == 0
    except:
        return False

# Extended scan with more IPs
for i in range(1, 30):
    ip = f'172.17.0.{i}'
    for port in [8929, 3000, 80, 443]:
        if check_port(ip, port):
            print(f'{ip}:{port} OPEN')
"

python3 -c "
import requests

# The GCE host is at 10.0.0.2, let's try accessing services there
ip = '10.0.0.2'

for port in [8929, 3000, 80, 443]:
    try:
        response = requests.get(f'http://{ip}:{port}/', timeout=2)
        print(f'{ip}:{port}: Status {response.status_code}')
    except requests.exceptions.ConnectionError as e:
        print(f'{ip}:{port}: Connection refused')
    except requests.exceptions.ReadTimeout:
        print(f'{ip}:{port}: Timeout')
    except Exception as e:
        print(f'{ip}:{port}: {type(e).__name__}')
"

